"use client";

import { motion, useScroll, useTransform } from "framer-motion";
import { useRef } from "react";
import Link from "next/link";
import { AnimatedSection, SectionDivider, SectionHeading } from "@/components/ui";
import { Star, ChefHat, Utensils, Wine, Clock, Award } from "lucide-react";

/* ═══════════════════════════════════════
   HERO
═══════════════════════════════════════ */
function Hero() {
  const ref = useRef(null);
  const { scrollYProgress } = useScroll({ target: ref, offset: ["start start", "end start"] });
  const y = useTransform(scrollYProgress, [0, 1], ["0%", "20%"]);
  const opacity = useTransform(scrollYProgress, [0, 0.8], [1, 0]);

  return (
    <section ref={ref} className="hero-section">
      {/* Parallax background */}
      <motion.div
        style={{ y, position: "absolute", inset: 0, backgroundImage: "url('https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=1920&q=80')", backgroundSize: "cover", backgroundPosition: "center" }}
      />
      {/* Gradient overlay */}
      <div className="hero-overlay" />

      {/* Content */}
      <motion.div style={{ opacity }} className="hero-content">
        <motion.p
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.3, duration: 0.8 }}
          className="hero-subheading"
        >
          A Culinary Masterpiece
        </motion.p>

        <motion.h1
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.5, duration: 0.8 }}
          className="hero-heading"
          style={{ color: "#fff", marginBottom: "24px" }}
        >
          Aurora{" "}
          <span className="gold-gradient-text" style={{ fontStyle: "italic" }}>
            Dining
          </span>
        </motion.h1>

        <motion.p
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.7, duration: 0.8 }}
          style={{ color: "rgba(232,224,208,0.65)", fontSize: "18px", fontFamily: "'Cormorant Garamond', serif", fontWeight: 300, maxWidth: "600px", margin: "0 auto 48px", lineHeight: 1.7, letterSpacing: "0.03em" }}
        >
          Where culinary artistry meets timeless elegance — an unforgettable dining experience awaits
        </motion.p>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.9, duration: 0.8 }}
          className="hero-cta-group"
        >
          <Link href="/contact" className="btn-gold">Reserve a Table</Link>
          <Link href="/menu" className="btn-outline">View Menu</Link>
        </motion.div>
      </motion.div>

      {/* Scroll indicator */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 1.5 }}
        style={{ position: "absolute", bottom: "48px", left: "50%", transform: "translateX(-50%)", display: "flex", flexDirection: "column", alignItems: "center", gap: "12px" }}
      >
        <span style={{ color: "rgba(201,169,110,0.5)", fontSize: "10px", letterSpacing: "0.3em", textTransform: "uppercase" }}>Scroll</span>
        <motion.div
          animate={{ y: [0, 8, 0] }}
          transition={{ repeat: Infinity, duration: 1.5 }}
          style={{ width: "1px", height: "40px", background: "linear-gradient(to bottom, rgba(201,169,110,0.5), transparent)" }}
        />
      </motion.div>
    </section>
  );
}

